1	type Item = { type: string; enchantment?: number; cursed?: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Step = {
4	  op: string;
5	  items?: Item[];
6	  policy?: number;
7	  incident?: { cause?: string; damages: Damage[] };
8	};
9	type Scenario = {
10	  customer?: { yearsWithMHPCO?: number };
11	  steps: Step[];
12	};
13	
14	const PROCESSING_FEE = 5;
15	const DEDUCTIBLE_PER_DAMAGE = 100;
16	const CAP_MULTIPLIER = 2;
17	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	const BLOCK_OF_3_PRICE = 60;
34	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
37	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const CURSE_SURCHARGE_RATE = 0.5;
40	const LOYALTY_THRESHOLD_YEARS = 2;
41	const LOYALTY_DISCOUNT_RATE = 0.2;
42	const FIRST_INSURANCE_RATE = 0.1;
43	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
44	
45	function quotePremium(
46	  items: Item[],
47	  yearsWithMHPCO: number,
48	  quoteIndex: number,
49	): number {
50	  const countsByType: Record<string, number> = {};
51	  for (const item of items) {
52	    if (!(item.type in BASE_PREMIUM_BY_ITEM_TYPE)) {
53	      throw new Error(`Unknown item type: ${item.type}`);
54	    }
55	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
56	  }
57	  let policyBase = 0;
58	  for (const [type, count] of Object.entries(countsByType)) {
59	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
60	      policyBase += BLOCK_OF_3_PRICE;
61	    } else {
62	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
63	    }
64	  }
65	  let itemSurcharges = 0;
66	  for (const item of items) {
67	    let surchargeRate = 0;
68	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
69	      surchargeRate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
70	    }
71	    if (item.cursed) {
72	      surchargeRate += CURSE_SURCHARGE_RATE;
73	    }
74	    itemSurcharges += surchargeRate * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
75	  }
76	  const firstInsuranceCharge = policyBase * FIRST_INSURANCE_RATE;
77	  const loyaltyDiscount =
78	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
79	  const followUpDiscount = quoteIndex >= 1 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
80	  return (
81	    Math.ceil(
82	      policyBase + itemSurcharges + firstInsuranceCharge - loyaltyDiscount - followUpDiscount,
83	    ) + PROCESSING_FEE
84	  );
85	}
86	
87	function adjustForEnchantment(amount: number, insuredItem: Item | undefined): number {
88	  if ((insuredItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
89	    return amount * HIGH_ENCHANTMENT_PAYOUT_RATE;
90	  }
91	  return amount;
92	}
93	
94	function initialCapFor(policyItems: Item[]): number {
95	  const insuranceSum = policyItems.reduce(
96	    (sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type],
97	    0,
98	  );
99	  return CAP_MULTIPLIER * insuranceSum;
100	}
101	
102	function reimbursementFor(damage: Damage, policyItems: Item[]): number {
103	  if (damage.amount < 0) {
104	    throw new Error(`Negative damage amount: ${damage.amount}`);
105	  }
106	  const insuredItem = policyItems.find((item) => item.type === damage.itemType);
107	  if (insuredItem === undefined) {
108	    throw new Error(`Claim references item type not in policy: ${damage.itemType}`);
109	  }
110	  const adjustedAmount = adjustForEnchantment(damage.amount, insuredItem);
111	  return Math.max(0, adjustedAmount - DEDUCTIBLE_PER_DAMAGE);
112	}
113	
114	function processClaim(
115	  claimStep: Step,
116	  steps: Step[],
117	  remainingCapByPolicy: Record<number, number>,
118	): { payout: number; remainingCap: number } {
119	  const policyIndex = claimStep.policy!;
120	  const policyItems = steps[policyIndex].items ?? [];
121	  if (!(policyIndex in remainingCapByPolicy)) {
122	    remainingCapByPolicy[policyIndex] = initialCapFor(policyItems);
123	  }
124	  const damages = claimStep.incident?.damages ?? [];
125	  const grossPayout = damages.reduce(
126	    (sum, damage) => sum + reimbursementFor(damage, policyItems),
127	    0,
128	  );
129	  const payout = Math.min(
130	    Math.floor(grossPayout),
131	    remainingCapByPolicy[policyIndex],
132	  );
133	  remainingCapByPolicy[policyIndex] -= payout;
134	  return { payout, remainingCap: remainingCapByPolicy[policyIndex] };
135	}
136	
137	export function processScenario(scenario: unknown): unknown {
138	  const { customer, steps } = scenario as Scenario;
139	  const yearsWithMHPCO = customer?.yearsWithMHPCO ?? 0;
140	  const remainingCapByPolicy: Record<number, number> = {};
141	  let quoteIndex = 0;
142	  const results = steps.map((step) => {
143	    if (step.op === "claim") {
144	      return processClaim(step, steps, remainingCapByPolicy);
145	    }
146	    const premium = quotePremium(step.items ?? [], yearsWithMHPCO, quoteIndex);
147	    quoteIndex += 1;
148	    return { premium };
149	  });
150	  return { results };
151	}
